<?php
/* TimeWalk Japan module: self-guided walks */
if(!defined('ABSPATH'))exit;
final class TWJ_Self_Guides{
 const DATA='https://raw.githubusercontent.com/tsu58-rgb/timewalk-meetup-events/main/self-guides.json';
 const VER='1.0.0';
 function __construct(){add_action('wp_loaded',array($this,'publish'),30);add_shortcode('timewalk_self_guided_walks',array($this,'listing'));add_shortcode('timewalk_self_guide_map',array($this,'map'));add_action('wp_enqueue_scripts',array($this,'assets'));add_filter('document_title_parts',array($this,'title'),20);add_action('wp_head',array($this,'meta'),2);}
 private function data($force=false){if(!$force&&is_array($c=get_transient('twj_guides_data')))return$c;$r=wp_remote_get(add_query_arg('twj',(string)time(),self::DATA),array('timeout'=>25,'headers'=>array('Cache-Control'=>'no-cache','User-Agent'=>'TimeWalkJapan-Guides')));if(is_wp_error($r))return array();$d=json_decode((string)wp_remote_retrieve_body($r),true);if(!is_array($d)||empty($d['guides'])||empty($d['maps']))return array();set_transient('twj_guides_data',$d,HOUR_IN_SECONDS);return$d;}
 private function content($g){$out='';if(empty($g['content_urls'])||!is_array($g['content_urls']))return$out;foreach($g['content_urls'] as $url){$r=wp_remote_get(add_query_arg('twj',(string)time(),$url),array('timeout'=>25,'headers'=>array('Cache-Control'=>'no-cache','User-Agent'=>'TimeWalkJapan-GuideContent')));if(is_wp_error($r))return'';$p=(string)wp_remote_retrieve_body($r);if($p==='')return'';$out.=$p;}return$out;}
 private function term($name,$tax,$slug){$t=term_exists($name,$tax);if(!$t)$t=wp_insert_term($name,$tax,array('slug'=>$slug));return is_array($t)?(int)$t['term_id']:(int)$t;}
 function publish(){$d=$this->data(true);if(!$d)return;$version=isset($d['version'])?(string)$d['version']:self::VER;if((string)get_option('twj_guides_published_version','')===$version)return;$cat=$this->term('Tokyo Guides','category','tokyo-guides');$tag=$this->term('Historical Walks','post_tag','historical-walks');$ok=0;foreach($d['guides'] as $g){$content=$this->content($g);if($content==='')continue;$old=get_page_by_path($g['slug'],OBJECT,'post');$a=array('post_type'=>'post','post_status'=>'publish','post_title'=>$g['title'],'post_name'=>$g['slug'],'post_content'=>$content,'post_excerpt'=>$g['short'],'post_category'=>$cat?array($cat):array(),'tags_input'=>$tag?array($tag):array());if($old)$a['ID']=$old->ID;$id=$old?wp_update_post(wp_slash($a),true):wp_insert_post(wp_slash($a),true);if(is_wp_error($id)||!$id)continue;foreach(array('_twj_self_guide'=>'1','_twj_guide_id'=>$g['guide_id'],'_twj_area'=>$g['area'],'_twj_area_slug'=>$g['area_slug'],'_twj_short_description'=>$g['short'],'_twj_distance'=>$g['distance'],'_twj_duration'=>$g['duration'],'_twj_seo_title'=>$g['seo_title'],'_twj_meta_description'=>$g['meta_description'],'_yoast_wpseo_title'=>$g['seo_title'],'_yoast_wpseo_metadesc'=>$g['meta_description'],'rank_math_title'=>$g['seo_title'],'rank_math_description'=>$g['meta_description']) as $k=>$v)update_post_meta($id,$k,$v);$u=get_permalink($id);update_post_meta($id,'_yoast_wpseo_canonical',$u);update_post_meta($id,'rank_math_canonical_url',$u);$ok++;}if($ok===count($d['guides'])){$content='<!-- wp:paragraph --><p>Explore Tokyo through independent historical walks. Use an entire guide or choose only the places and explanations that fit your interests.</p><!-- /wp:paragraph --><!-- wp:shortcode -->[timewalk_self_guided_walks]<!-- /wp:shortcode -->';$p=get_page_by_path('self-guided-walks',OBJECT,'page');$a=array('post_type'=>'page','post_status'=>'publish','post_title'=>'Self-Guided Walks','post_name'=>'self-guided-walks','post_content'=>$content);if($p)$a['ID']=$p->ID;$p?wp_update_post(wp_slash($a)):wp_insert_post(wp_slash($a));update_option('twj_guides_published_version',$version,false);flush_rewrite_rules(false);}}
 function listing(){$q=new WP_Query(array('post_type'=>'post','post_status'=>'publish','posts_per_page'=>100,'meta_key'=>'_twj_self_guide','meta_value'=>'1','orderby'=>'title','order'=>'ASC'));$areas=array();$cards='';while($q->have_posts()){$q->the_post();$id=get_the_ID();$area=(string)get_post_meta($id,'_twj_area',true);$slug=(string)get_post_meta($id,'_twj_area_slug',true);$short=(string)get_post_meta($id,'_twj_short_description',true);if($area)$areas[$slug]=$area;$search=strtolower(wp_strip_all_tags(get_the_title().' '.$area.' '.$short));$cards.='<article class="twj-guide-card" data-area="'.esc_attr($slug).'" data-search="'.esc_attr($search).'"><a class="twj-guide-card__link" href="'.esc_url(get_permalink()).'"><div class="twj-guide-card__visual"><span>'.esc_html($area).'</span></div><div class="twj-guide-card__body"><p class="twj-guide-card__area">'.esc_html($area).'</p><h2>'.esc_html(get_the_title()).'</h2><p>'.esc_html($short).'</p></div></a></article>';}wp_reset_postdata();ksort($areas);$options='<option value="">All areas</option>';foreach($areas as $s=>$a)$options.='<option value="'.esc_attr($s).'">'.esc_html($a).'</option>';return '<section class="twj-guides"><div class="twj-guide-tools"><label><span>Search</span><input type="search" class="twj-guide-keyword" placeholder="Search walks"></label><label><span>Area</span><select class="twj-guide-area">'.$options.'</select></label></div><div class="twj-guide-grid">'.$cards.'</div><p class="twj-guide-empty" hidden>No walks match your search.</p></section>';}
 function map($atts){$a=shortcode_atts(array('guide'=>''),$atts);$d=$this->data();$id=(string)$a['guide'];if(empty($d['maps'][$id]))return'';$stops=$d['maps'][$id];$dom='twj-map-'.strtolower(str_replace('_','-',$id));return '<div class="twj-map-note"><strong>Map note:</strong> Pins and the dashed line show only the suggested article order. They are not turn-by-turn directions. Pins identify the general site and may not mark a public entrance.</div><div id="'.esc_attr($dom).'" class="twj-guide-map" data-stops="'.esc_attr(wp_json_encode($stops)).'"></div>';}
 function title($parts){if(is_singular()){global$post;$t=(string)get_post_meta($post->ID,'_twj_seo_title',true);if($t)$parts['title']=$t;}return$parts;}
 function meta(){if(!is_singular())return;global$post;$d=(string)get_post_meta($post->ID,'_twj_meta_description',true);if($d)echo '<meta name="description" content="'.esc_attr($d).'">\n<link rel="canonical" href="'.esc_url(get_permalink($post)).'">\n';}
 function assets(){wp_enqueue_style('leaflet','https://unpkg.com/leaflet@1.9.4/dist/leaflet.css',array(),'1.9.4');wp_enqueue_script('leaflet','https://unpkg.com/leaflet@1.9.4/dist/leaflet.js',array(),'1.9.4',true);wp_register_style('twj-guides',false,array('leaflet'),self::VER);wp_enqueue_style('twj-guides');wp_add_inline_style('twj-guides','.twj-guide-tools{display:flex;gap:12px;flex-wrap:wrap;margin:22px 0}.twj-guide-tools label{display:flex;flex-direction:column;gap:5px;font-size:.78rem;font-weight:700}.twj-guide-tools input,.twj-guide-tools select{min-width:220px;padding:10px;border:1px solid #ccd3dc;border-radius:8px;background:#fff}.twj-guide-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:18px}.twj-guide-card{border:1px solid #e2e7ed;border-radius:12px;overflow:hidden;background:#fff;box-shadow:0 6px 18px rgba(23,32,51,.06)}.twj-guide-card__link{display:block;color:inherit!important;text-decoration:none!important}.twj-guide-card__visual{aspect-ratio:16/9;background:linear-gradient(135deg,#173b57,#326f82);display:flex;align-items:flex-end;padding:14px;color:#fff;font-weight:700}.twj-guide-card__body{padding:14px}.twj-guide-card__area{margin:0 0 5px!important;color:#607080;font-size:.75rem;font-weight:700;text-transform:uppercase;letter-spacing:.05em}.twj-guide-card h2{margin:0 0 8px!important;font-size:1.05rem;line-height:1.35}.twj-guide-card__body>p:last-child{margin:0!important;color:#536170;font-size:.88rem;line-height:1.55}.twj-guide-map{height:520px;max-height:70vh;min-height:360px;border:1px solid #d8dee6;border-radius:12px;overflow:hidden}.twj-map-note{font-size:.92rem;color:#4b5563;margin:.65rem 0 1rem}.twj-number-pin{display:flex;align-items:center;justify-content:center;width:30px;height:30px;border-radius:50%;background:#173b57;color:#fff;border:2px solid #fff;box-shadow:0 1px 5px rgba(0,0,0,.35);font-weight:700}.twj-walk-glance,.twj-meetup-cta{padding:18px;border-radius:10px;background:#f3f6f8}.twj-coordinate{font-size:.85rem}@media(max-width:800px){.twj-guide-grid{grid-template-columns:repeat(2,minmax(0,1fr))}.twj-guide-tools label{flex:1}.twj-guide-tools input,.twj-guide-tools select{width:100%;min-width:0}}@media(max-width:520px){.twj-guide-grid{grid-template-columns:1fr}}');wp_register_script('twj-guides',false,array('leaflet'),self::VER,true);wp_enqueue_script('twj-guides');wp_add_inline_script('twj-guides',"document.addEventListener('DOMContentLoaded',function(){document.querySelectorAll('.twj-guide-map').forEach(function(el){if(el.dataset.ready)return;el.dataset.ready='1';var s=JSON.parse(el.dataset.stops||'[]'),m=L.map(el,{scrollWheelZoom:false}),pts=[];L.tileLayer('https://cyberjapandata.gsi.go.jp/xyz/std/{z}/{x}/{y}.png',{attribution:'地理院タイル（国土地理院）',maxZoom:18}).addTo(m);s.forEach(function(x){var i=L.divIcon({className:'',html:'<span class=\"twj-number-pin\">'+x.order+'</span>',iconSize:[30,30],iconAnchor:[15,15]});L.marker([x.lat,x.lng],{icon:i}).addTo(m).bindPopup('<strong>'+x.order+'. '+x.name+'</strong><br><a href=\"#'+x.anchorId+'\">Read this stop</a> · <a href=\"'+x.googleMapsUrl+'\" target=\"_blank\" rel=\"noopener\">Open coordinates</a>');pts.push([x.lat,x.lng]);});L.polyline(pts,{color:'#356b8c',weight:3,opacity:.65,dashArray:'7 8'}).addTo(m);m.fitBounds(pts,{padding:[28,28]});});var key=document.querySelector('.twj-guide-keyword'),area=document.querySelector('.twj-guide-area'),cards=[].slice.call(document.querySelectorAll('.twj-guide-card')),empty=document.querySelector('.twj-guide-empty');function filter(){var k=(key&&key.value||'').toLowerCase().trim(),a=area&&area.value||'',n=0;cards.forEach(function(c){var show=(!k||(c.dataset.search||'').indexOf(k)>-1)&&(!a||c.dataset.area===a);c.hidden=!show;if(show)n++;});if(empty)empty.hidden=n!==0;}if(key)key.addEventListener('input',filter);if(area)area.addEventListener('change',filter);});");}
}
new TWJ_Self_Guides();
